mapper.select:
SELECT B1.* FROM ( SELECT A1.*, ROW_NUMBER() OVER () AS PAGEINDEX FROM ( SELECT request.REQUEST_NO AS requestNo, /* 요청번호 */ request.REQUEST_NO AS requestOrgNo, /* 요청번호 */ request.OBJECT_TYPE AS objectType, /* 자료유형 */ FN_GET_CD_NM('productionObjectType', REPLACE(request.OBJECT_TYPE, 'PRODUCT_', ''), #{sessionLang}) AS objectTypeNm, companyUser.USER_CD AS companyUserCd, /* 업체담당자 */ companyUser.USER_NM AS companyUserNm, /* 업체담당자 */ acceptDetail.ACTUAL_USER_CD AS purchaserUserCd, /* 구매담당자 */ acceptUser.USER_NM AS purchaserUserNm, /* 구매담당자 */ (SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT') AS deployUserNm, /* 배포자 */ request.INSERT_DT AS requestDt, /* 요청일자 */ request.APPROVAL_DT AS approvalDt, /* 결재일자 */ request.STATUS_CD AS statusCd, /* 결재상태 */ FN_GET_CD_NM('requestStatusCd', request.STATUS_CD, #{sessionLang}) AS statusNm, /* 결재상태명 */ request.VENDOR_ACCEPT_YN AS vendorAcceptYn, /* 업체접수여부 */ FN_GET_CD_NM('vendorAcceptYn', request.VENDOR_ACCEPT_YN, #{sessionLang}) AS vendorAcceptNm, /* 업체접수여부 */ request.VENDOR_ACCEPT_USER_CD AS vendorAcceptUserCd, /* 업체접수자 */ (SELECT acceptUser.USER_NM FROM DOCS_USER acceptUser WHERE acceptUser.USER_CD = request.VENDOR_ACCEPT_USER_CD) AS vendorAcceptUserNm, /* 업체접수자 */ request.VENDOR_ACCEPT_DT AS vendorAcceptDt, /* 업체접수일 */ CASE WHEN deployInfo.DEPLOY_NORMAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.normalArea' AND lang.LANG_TYPE = 'ko') WHEN deployInfo.DEPLOY_SPECIAL_YN = 'Y' THEN (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.specialArea' AND lang.LANG_TYPE = 'ko') ELSE (SELECT LANG_DESC FROM DOCS_LANG lang WHERE lang.LANG_CD = 'combo.deployType.viewing' AND lang.LANG_TYPE = 'ko') END AS distributeTypeNm FROM DOCS_REQUEST request INNER JOIN DOCS_REQUEST_DETAIL acceptDetail ON acceptDetail.REQUEST_NO = request.REQUEST_NO AND acceptDetail.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD INNER JOIN DOCS_USER acceptUser ON acceptUser.USER_CD = acceptDetail.ORIGINAL_USER_CD AND acceptDetail.APPROVAL_STATUS_CD = 'ACCEPT' WHERE request.REQUEST_TYPE = 'DISTRIBUTION' AND request.OBJECT_TYPE IN ('PRODUCT_DOC', 'PRODUCT_SW') AND request.DEPLOY_COMPANY_CD = #{sessionUser.companyCd} /* 로그인 한 사용자의 업체 정보만 표시 */
AND request.INSERT_DT BETWEEN TO_TIMESTAMP(#{requestStartDt}, 'YYYY-MM-DD') AND TO_TIMESTAMP(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
ORDER BY requestDt DESC, requestNo DESC
ORDER BY ${sortColumn} ${order}
) A1 ) B1 WHERE B1.PAGEINDEX BETWEEN #{start} AND #{end};

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT B1.* FROM ( SELECT A1.* FROM ( SELECT request.REQUEST_NO AS requestNo /* 요청번호 */ , request.REQUEST_NO AS requestOrgNo /* 요청번호 */ , request.OBJECT_TYPE AS objectType /* 자료유형 */ , companyUser.USER_CD AS companyUserCd /* 업체담당자 */ , companyUser.USER_NM AS companyUserNm /* 업체담당자 */ , acceptDetail.ACTUAL_USER_CD AS purchaserUserCd /* 구매담당자 */ , acceptUser.USER_NM AS purchaserUserNm /* 구매담당자*/ , ( SELECT USER_NM FROM DOCS_REQUEST_DETAIL requestDetail INNER JOIN DOCS_USER docsUser ON docsUser.USER_CD = requestDetail.ACTUAL_USER_CD WHERE requestDetail.REQUEST_NO = request.REQUEST_NO AND requestDetail.APPROVAL_STATUS_CD = 'ACCEPT' ) AS deployUserNm /* 배포자 */ , request.INSERT_DT AS requestDt /* 요청일자 */ , request.APPROVAL_DT AS approvalDt /* 결재일자 */ , request.STATUS_CD AS statusCd /* 결재상태 */ , request.VENDOR_ACCEPT_YN AS vendorAcceptYn /* 업체접수여부 */ , FN_GET_CD_NM('vendorAcceptYn', request.VENDOR_ACCEPT_YN, #{sessionLang}) AS vendorAcceptNm /* 업체접수여부 */ , request.VENDOR_ACCEPT_USER_CD AS vendorAcceptUserCd /* 업체접수자 */ , (SELECT acceptUser.USER_NM FROM DOCS_USER acceptUser WHERE acceptUser.USER_CD = request.VENDOR_ACCEPT_USER_CD) AS vendorAcceptUserNm /* 업체접수자 */ , request.VENDOR_ACCEPT_DT AS vendorAcceptDt /* 업체접수일 */ FROM DOCS_REQUEST request INNER JOIN DOCS_REQUEST_DETAIL acceptDetail ON acceptDetail.REQUEST_NO = request.REQUEST_NO AND acceptDetail.APPROVAL_STATUS_CD = 'ACCEPT' INNER JOIN DOCS_REQUEST_DEPLOY deployInfo ON deployInfo.REQUEST_NO = request.REQUEST_NO INNER JOIN DOCS_USER companyUser ON companyUser.USER_CD = deployInfo.DEPLOY_USER_CD INNER JOIN DOCS_USER acceptUser ON acceptUser.USER_CD = acceptDetail.ORIGINAL_USER_CD AND acceptDetail.APPROVAL_STATUS_CD = 'ACCEPT' WHERE REQUEST_TYPE = 'DISTRIBUTION' AND OBJECT_TYPE IN ('PRODUCT_DOC', 'PRODUCT_SW') AND request.DEPLOY_COMPANY_CD = #{sessionUser.companyCd} /* 로그인 한 사용자의 업체 정보만 표시 */
AND request.INSERT_DT BETWEEN TO_TIMESTAMP(#{requestStartDt}, 'YYYY-MM-DD') AND TO_TIMESTAMP(#{requestEndDt}, 'YYYY-MM-DD') + INTERVAL '1 day'
) A1 WHERE 1=1
AND companyUserCd = #{requestUserCd}
AND purchaserUserCd = #{purchaserUserCd}
AND statusCd = #{statusCd}
AND objectType = 'PRODUCT_' || #{objectType}
) B1 ) C1
